import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos } from '../services/productoService';
import { registrarVenta } from '../services/ventaService';

const Ventas = () => {
    const navigate = useNavigate();
    const [productos, setProductos] = useState([]);
    const [seleccion, setSeleccion] = useState({
        productoId: '', codigo: '', nombre: '', precio: 0, cantidad: 1, stockDisponible: 0
    });
    // ✅ Lista de productos agregados a la venta actual
    const [listaVenta, setListaVenta] = useState([]);
    const [pago, setPago] = useState({ efectivo: 0, cambio: 0 });

    useEffect(() => {
        if (!localStorage.getItem('usuarioLogueado')) {
            navigate("/");
        } else {
            obtenerProductos().then(setProductos);
        }
    }, [navigate]);

    // Calcular el total de toda la lista
    const totalVenta = listaVenta.reduce((acc, item) => acc + (item.precio * item.cantidad), 0);

    useEffect(() => {
        setPago(prev => ({ ...prev, cambio: prev.efectivo > 0 ? prev.efectivo - totalVenta : 0 }));
    }, [pago.efectivo, totalVenta]);

    const seleccionarProducto = (e) => {
        const prod = productos.find(p => p.id.toString() === e.target.value);
        if (prod) {
            setSeleccion({
                productoId: prod.id, codigo: prod.codigo, nombre: prod.nombre,
                precio: prod.precioVenta, cantidad: 1, stockDisponible: prod.stock
            });
        }
    };

    // ✅ Función para agregar a la lista antes de cobrar
    const agregarALista = () => {
        if (!seleccion.productoId) return alert("Selecciona un producto");
        if (seleccion.cantidad > seleccion.stockDisponible) return alert("No hay suficiente stock");
        
        setListaVenta([...listaVenta, { ...seleccion }]);
        // Limpiar selección para el siguiente producto
        setSeleccion({ productoId: '', codigo: '', nombre: '', precio: 0, cantidad: 1, stockDisponible: 0 });
    };

    const generarTicketPDF = (ventaFinal) => {
        import('jspdf').then(({ default: jsPDF }) => {
            const doc = new jsPDF({ unit: 'mm', format: [80, 200] });
            let y = 10;
            doc.setFont('courier', 'bold');
            doc.text('ISLA TECNOLÓGICA', 40, y, { align: 'center' });
            y += 10;
            doc.setFontSize(8);
            doc.text('--------------------------------', 40, y, { align: 'center' });
            y += 5;
            
            // Listar cada producto en el ticket
            listaVenta.forEach(item => {
                doc.text(`${item.cantidad} x ${item.nombre}`, 5, y);
                doc.text(`$${(item.precio * item.cantidad).toFixed(2)}`, 75, y, { align: 'right' });
                y += 5;
            });

            y += 5;
            doc.setFontSize(10);
            doc.text(`TOTAL: MXN $${totalVenta.toFixed(2)}`, 75, y, { align: 'right' });
            y += 7;
            doc.text(`Efectivo: $${parseFloat(pago.efectivo).toFixed(2)}`, 75, y, { align: 'right' });
            y += 5;
            doc.text(`Cambio: $${pago.cambio.toFixed(2)}`, 75, y, { align: 'right' });
            
            doc.save(`ticket-${Date.now()}.pdf`);
        });
    };

    const finalizarVenta = async () => {
        if (listaVenta.length === 0) return alert("El carrito está vacío");
        if (pago.efectivo < totalVenta) return alert("Efectivo insuficiente");

        // Registrar cada producto en el backend
        for (let item of listaVenta) {
            const datos = {
                codigoProducto: item.codigo,
                nombreProducto: item.nombre,
                cantidad: item.cantidad,
                precioVenta: item.precio,
                vendedorMatricula: localStorage.getItem('usuarioLogueado')
            };
            await registrarVenta(datos);
        }

        generarTicketPDF();
        alert("✅ Venta completada");
        setListaVenta([]);
        setPago({ efectivo: 0, cambio: 0 });
    };

    return (
        <div style={{ padding: '30px', fontFamily: 'Arial', maxWidth: '1000px', margin: '0 auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                <button onClick={() => navigate("/inventario")} style={{ backgroundColor: '#6c757d', color: 'white', padding: '10px 15px', border: 'none', borderRadius: '8px', cursor: 'pointer' }}>⬅️ Inventario</button>
                <h2 style={{ color: '#007bff' }}>🛒 Terminal de Venta - Isla Tecnológica</h2>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                {/* SECCIÓN DE SELECCIÓN */}
                <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '12px', border: '1px solid #ddd' }}>
                    <label><b>Producto</b></label>
                    <select value={seleccion.productoId} onChange={seleccionarProducto} style={{ width: '100%', padding: '12px', margin: '10px 0' }}>
                        <option value="">-- Buscar --</option>
                        {productos.map(p => <option key={p.id} value={p.id}>{p.nombre} ({p.codigo})</option>)}
                    </select>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                        <input type="number" placeholder="Cant" value={seleccion.cantidad} onChange={e => setSeleccion({...seleccion, cantidad: e.target.value})} style={{ padding: '10px' }} />
                        <input type="number" placeholder="Precio $" value={seleccion.precio} onChange={e => setSeleccion({...seleccion, precio: e.target.value})} style={{ padding: '10px' }} />
                    </div>

                    <button onClick={agregarALista} style={{ width: '100%', padding: '15px', background: '#007bff', color: 'white', border: 'none', borderRadius: '8px', marginTop: '15px', fontWeight: 'bold', cursor: 'pointer' }}>
                        ➕ AGREGAR A LA LISTA
                    </button>
                </div>

                {/* RESUMEN Y COBRO */}
                <div style={{ background: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)' }}>
                    <h4>Lista de Venta</h4>
                    <div style={{ maxHeight: '150px', overflowY: 'auto', marginBottom: '15px' }}>
                        {listaVenta.map((item, index) => (
                            <div key={index} style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid #eee', padding: '5px 0' }}>
                                <span>{item.cantidad}x {item.nombre}</span>
                                <b>${(item.precio * item.cantidad).toFixed(2)}</b>
                            </div>
                        ))}
                    </div>
                    <div style={{ fontSize: '22px', fontWeight: 'bold', textAlign: 'right', color: '#28a745' }}>
                        TOTAL: ${totalVenta.toFixed(2)}
                    </div>

                    <div style={{ marginTop: '15px' }}>
                        <label>Paga con:</label>
                        <input type="number" value={pago.efectivo} onChange={e => setPago({...pago, efectivo: e.target.value})} style={{ width: '100%', padding: '10px', fontSize: '18px' }} />
                        <p>Cambio: <b style={{ color: 'blue' }}>${pago.cambio.toFixed(2)}</b></p>
                    </div>

                    <button onClick={finalizarVenta} style={{ width: '100%', padding: '15px', background: '#28a745', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer', fontSize: '18px' }}>
                        ✅ COBRAR Y GENERAR TICKET
                    </button>
                </div>
            </div>
        </div>
    );
};

export default Ventas;
